            i === current
              ? "w-6 bg-primary"
              : "w-1.5 bg-muted-foreground/30"
          )}
        />
      ))}
    </div>
  );
}
```

### Step 4: Apply to Mobile Feature Cards
```tsx
function MobileFeatureCarousel({ features }) {
  const { containerRef, bind, currentPage } = useSwipeScroll({
    itemsPerPage: 1,
  });

  return (
    <div className="overflow-hidden">
      <div
        ref={containerRef}
        {...bind()}
        className="flex gap-4 overflow-x-auto snap-x snap-mandatory scrollbar-hide"
        style={{ touchAction: "pan-y pinch-zoom" }}
      >
        {features.map((feature) => (
          <div key={feature.id} className="snap-center shrink-0 w-[85vw]">
            <FeatureCard {...feature} />
          </div>
        ))}
      </div>
      <SwipeIndicator current={currentPage} total={features.length} />
    </div>
  );
}
```

### Step 5: Add CSS for Smooth Scrolling
```css
/* In globals.css */
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}
.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

.snap-x {
  scroll-snap-type: x mandatory;
}

.snap-center {
  scroll-snap-align: center;
}

.snap-start {
  scroll-snap-align: start;
}
```

